Extract to a single hook (hooks/useStudioOpenId.ts):
```ts
import { useSearchParams } from 'react-router-dom';
export function useStudioOpenId(drafts: {id:string}[]) {
  const [params, setParams] = useSearchParams();
  const openId = params.get('open');
  const setOpenId = useCallback((id: string|null) => {
    setParams(prev => { const p = new URLSearchParams(prev); if(id) p.set('open', id); else p.delete('open'); return p; }, { replace: false });
  }, [setParams]);
  // If the deeplink target isn't in drafts yet, keep it; once drafts load and don't contain it, drop it.
  useEffect(() => { if (openId && drafts.length > 0 && !drafts.some(d => d.id === openId)) setOpenId(null); }, [drafts, openId, setOpenId]);
  return [openId, setOpenId] as const;
}
```
Replace lines 191-219 in PostStudioPanel and 183-210 in LeadMagnetStudioPanel with `const [openId, setOpenId] = useStudioOpenId(drafts);`. The race is gone because URL is source-of-truth, not local state. Back button works because replace:false pushes history.
